        //         <p>🔥 Belajar React itu keren • Frontend Developer • CSS Animation 🔥</p>
        //     </div>

        //     <div className={style.glassBox}>
        //         <h2>Glass Box</h2>
        //         <p>Ini kotak transparan dengan efek blur</p>
        //     </div>

        // </div>
    )
}

export default Projects;
